('additional-maths:6-1-counting-permutations-and-combinations:fib:889ae7e9', 'additional-maths', 'additional-maths:6-1-counting-permutations-and-combinations', '6.1 Counting, Permutations and Combinations', 'fib', 'fib', 2, '{"question": "In a permutation the ___B1___ of the objects matters, but in a combination it does ___B2___.", "blankOptions": {"B1": ["order", "n+1", "n-r", "n!"], "B2": ["permutation", "not", "factorial", "n!"]}}'::jsonb, '{"blanks": {"B1": "order", "B2": "not"}}'::jsonb),
('additional-maths:6-1-counting-permutations-and-combinations:fib:d6e9029b', 'additional-maths', 'additional-maths:6-1-counting-permutations-and-combinations', '6.1 Counting, Permutations and Combinations', 'fib', 'fib', 1, '{"question": "In the permutation formula \\( {}^nP_r = \\frac{n!}{(n-r)!} \\), the denominator is the factorial of ___B1___.", "blankOptions": {"B1": ["order", "n-r", "factorial", "combination"]}}'::jsonb, '{"blanks": {"B1": "n-r"}}'::jsonb),
('additional-maths:6-1-counting-permutations-and-combinations:fib:601109ed', 'additional-maths', 'additional-maths:6-1-counting-permutations-and-combinations', '6.1 Counting, Permutations and Combinations', 'fib', 'fib', 1, '{"question": "Compared with \\( {}^nP_r \\), the combination \\( {}^nC_r \\) divides by an extra ___B1___ to cancel the repeated orderings.", "blankOptions": {"B1": ["n-r", "order", "permutation", "r!"]}}'::jsonb, '{"blanks": {"B1": "r!"}}'::jsonb),
